import { useState, useEffect } from 'react';
import { motion } from 'framer-motion'; // For animations

const Hero = () => {
  const [isHovered, setIsHovered] = useState(false);
  const [scrollY, setScrollY] = useState(0);

  // Parallax effect on scroll
  useEffect(() => {
    const handleScroll = () => setScrollY(window.scrollY);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <section className="relative overflow-hidden min-h-[90vh] flex items-center justify-center">
      {/* Animated gradient background */}
      <div 
        className="absolute inset-0 bg-gradient-to-br from-purple-600 via-blue-500 to-teal-400 opacity-90"
        style={{
          transform: `translateY(${scrollY * 0.5}px)`, // Parallax effect
        }}
      />

      {/* Content container */}
      <motion.div 
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.8 }}
        className="relative z-10 text-center px-4 sm:px-6 lg:px-8 max-w-7xl mx-auto"
      >
        {/* Headline with text-shadow */}
        <h1 className="text-4xl sm:text-5xl md:text-6xl font-extrabold text-white mb-6 leading-tight tracking-tight">
          <span className="drop-shadow-2xl">Transform Your</span>{' '}
          <span className="text-transparent bg-clip-text bg-gradient-to-r from-yellow-300 to-amber-500">
            Digital Presence
          </span>
        </h1>

        {/* Subtitle */}
        <p className="text-lg md:text-xl text-white/90 max-w-2xl mx-auto mb-10">
          Build stunning websites faster than ever with our revolutionary tools and components.
        </p>

        {/* CTA Button with hover effect */}
        <motion.button
          whileHover={{ scale: 1.05 }}
          whileTap={{ scale: 0.95 }}
          onHoverStart={() => setIsHovered(true)}
          onHoverEnd={() => setIsHovered(false)}
          className={`relative px-8 py-4 rounded-full font-bold text-lg transition-all duration-300 ${
            isHovered 
              ? 'bg-white text-purple-600 shadow-xl'
              : 'bg-purple-800 text-white shadow-lg'
          }`}
        >
          <span className="relative z-10">Get Started Free</span>
          {/* Animated ring on hover */}
          {isHovered && (
            <motion.span
              initial={{ scale: 0.8, opacity: 0 }}
              animate={{ scale: 1.2, opacity: 0 }}
              transition={{ duration: 0.6 }}
              className="absolute inset-0 border-2 border-white rounded-full"
            />
          )}
        </motion.button>

        {/* Trust indicators */}
        <div className="mt-16 flex flex-wrap justify-center gap-8 items-center">
          {['Trusted by', '10,000+', 'Companies Worldwide'].map((text, i) => (
            <div key={i} className="flex items-center">
              <span className="text-white/70 text-sm sm:text-base">{text}</span>
              {i < 2 && <span className="mx-2 text-white/30">•</span>}
            </div>
          ))}
        </div>
      </motion.div>

      {/* Floating decorative elements */}
      <div className="absolute bottom-20 left-1/4 w-16 h-16 rounded-full bg-white/10 blur-xl" />
      <div className="absolute top-1/3 right-1/5 w-24 h-24 rounded-full bg-teal-400/20 blur-lg" />
    </section>
  );
};

export default Hero;
